import { expectDiagnostics } from "@typespec/compiler/testing";
import { describe, it } from "vitest";
import { Tester } from "../testing/test-host.js";

// Proper entity namespace fixture used consistently across tests
const TASK_ENTITY = `
  namespace Products.MyProduct.Entities.Task {
    @entity
    model Task { id: string; title: string; }
  }
  using Products.MyProduct.Entities.Task;
`;

describe("@projects", () => {
  describe("valid", () => {
    // a10n:blueprint Components.A10nBlueprintTypespecSdk.Tests.Decorators.T009.T009_01
    // a10n:blueprint:test Components.A10nBlueprintTypespecSdk.Operations.decorator_projects:Products.A10nBlueprintEngine.Features.SystemAuthoring.field_declares_proj:must
    // a10n:blueprint:test Components.A10nBlueprintTypespecSdk.Operations.decorator_test_case:Products.A10nBlueprintEngine.Features.SystemAuthoring.field_declares_proj:must
    // a10n:blueprint:test Components.A10nBlueprintTypespecSdk.Operations.decorator_projects:Products.A10nBlueprintEngine.Features.SystemAuthoring.projection_targets_domain:must
    // a10n:blueprint:test Components.A10nBlueprintTypespecSdk.Operations.decorator_test_case:Products.A10nBlueprintEngine.Features.SystemAuthoring.projection_targets_domain:must
    // a10n:blueprint:test Components.A10nBlueprintTypespecSdk.Operations.decorator_projects:Products.A10nBlueprintEngine.Features.SystemAuthoring.proj_field_compat:must
    // a10n:blueprint:test Components.A10nBlueprintTypespecSdk.Operations.decorator_test_case:Products.A10nBlueprintEngine.Features.SystemAuthoring.proj_field_compat:must
    // a10n:blueprint:test Components.A10nBlueprintTypespecSdk.Operations.decorator_projects:Products.A10nBlueprintEngine.Features.SystemAuthoring.field_projects_field:must
    // a10n:blueprint:test Components.A10nBlueprintTypespecSdk.Operations.decorator_test_case:Products.A10nBlueprintEngine.Features.SystemAuthoring.field_projects_field:must
    // a10n:blueprint:test-steps Components.A10nBlueprintTypespecSdk.Operations.decorator_projects
    it("on a model field referencing an @entity field", async () => {
      const runner = await Tester.createInstance();
      await runner.compile(`
        ${TASK_ENTITY}

        model TaskRow {
          @projects(Task.id)
          id: string;
        }
      `);
    });

    // a10n:blueprint Components.A10nBlueprintTypespecSdk.Tests.Decorators.T009.T009_11
    it("on a model field referencing multiple entity fields", async () => {
      const runner = await Tester.createInstance();
      await runner.compile(`
        ${TASK_ENTITY}

        model TaskRow {
          @projects(Task.id)
          id: string;
          @projects(Task.title)
          title: string;
        }
      `);
    });

    // a10n:blueprint Components.A10nBlueprintTypespecSdk.Tests.Decorators.T009.T009_13
    // a10n:blueprint:test Components.A10nBlueprintTypespecSdk.Operations.decorator_projects:Products.A10nBlueprintEngine.Features.SystemAuthoring.proj_source_system:must
    // a10n:blueprint:test Components.A10nBlueprintTypespecSdk.Operations.decorator_test_case:Products.A10nBlueprintEngine.Features.SystemAuthoring.proj_source_system:must
    // a10n:blueprint:test Components.A10nBlueprintTypespecSdk.Operations.decorator_projects:Products.A10nBlueprintEngine.Features.SystemAuthoring.projects_crosses_features:must
    // a10n:blueprint:test Components.A10nBlueprintTypespecSdk.Operations.decorator_test_case:Products.A10nBlueprintEngine.Features.SystemAuthoring.projects_crosses_features:must
    // a10n:blueprint:test Components.A10nBlueprintTypespecSdk.Operations.decorator_projects:Products.A10nBlueprintEngine.Features.SystemAuthoring.proj_not_namespace:must
    // a10n:blueprint:test Components.A10nBlueprintTypespecSdk.Operations.decorator_test_case:Products.A10nBlueprintEngine.Features.SystemAuthoring.proj_not_namespace:must
    // a10n:blueprint:test-steps Components.A10nBlueprintTypespecSdk.Operations.decorator_projects
    it("on a @tool op (a projecting-op-kind) referencing an @invariant op", async () => {
      // Component ops that enforce invariants may now carry @projects directly
      // (the invariant-mapping model). A @tool inside a @component is a projecting op kind.
      const runner = await Tester.createInstance();
      await runner.compile(`
        ${TASK_ENTITY}

        @feature
        namespace Products.MyProduct.Features.MyFeature {
          @invariant(#{
            predicate: "A {@Task} has an id.",
            why: "Reason.",
          })
          op task_has_id(): void;
        }

        @component(#{ type: ComponentType.Agent })
        namespace Components.MyAgent {
          @tool(#{ sequential: false })
          @projects(Products.MyProduct.Features.MyFeature.task_has_id)
          op do_task(): void;
        }
      `);
    });

    // a10n:blueprint Components.A10nBlueprintTypespecSdk.Tests.Decorators.T009.T009_14
    it("on an http_op (op in an Http ns inside a @component) referencing an @invariant", async () => {
      const runner = await Tester.createInstance();
      await runner.compile(`
        ${TASK_ENTITY}

        @feature
        namespace Products.MyProduct.Features.MyFeature {
          @invariant(#{
            predicate: "A {@Task} has an id.",
            why: "Reason.",
          })
          op task_has_id(): void;
        }

        @component(#{ type: ComponentType.Service })
        namespace Components.MyApiService {
          namespace Http {
            @projects(Products.MyProduct.Features.MyFeature.task_has_id)
            op get_task(): void;
          }
        }
      `);
    });

  });

  describe("invalid", () => {
    // a10n:blueprint Components.A10nBlueprintTypespecSdk.Tests.Decorators.T009.T009_04
    it("on a plain op that is not @testCase or @signal", async () => {
      const runner = await Tester.createInstance();
      const diagnostics = await runner.diagnose(`
        ${TASK_ENTITY}

        @feature
        namespace Products.MyProduct.Features.MyFeature {
          @invariant(#{
            predicate: "A {@Task} has an id.",
            why: "Reason.",
          })
          op task_has_id(): void;
        }

        @component(#{ type: ComponentType.Service })
        namespace Components.MyApiService {
          @projects(Products.MyProduct.Features.MyFeature.task_has_id)
          op arbitrary_op(): void;
        }
      `);
      expectDiagnostics(diagnostics, {
        code: "@a10n/blueprint-typespec/projects-op-not-proof",
        message: /arbitrary_op/,
      });
    });

    // a10n:blueprint Components.A10nBlueprintTypespecSdk.Tests.Decorators.T009.T009_12
    it("on a @flow op — not a proof op", async () => {
      const runner = await Tester.createInstance();
      const diagnostics = await runner.diagnose(`
        ${TASK_ENTITY}

        @feature
        namespace Products.MyProduct.Features.MyFeature {
          @invariant(#{
            predicate: "A {@Task} has an id.",
            why: "Reason.",
          })
          op task_has_id(): void;
        }

        @component(#{ type: ComponentType.Service })
        namespace Components.MyApiService {
          @flow
          @projects(Products.MyProduct.Features.MyFeature.task_has_id)
          op process_task(): void;
        }
      `);
      expectDiagnostics(diagnostics, {
        code: "@a10n/blueprint-typespec/projects-op-not-proof",
        message: /process_task/,
      });
    });

    // a10n:blueprint Components.A10nBlueprintTypespecSdk.Tests.Decorators.T009.T009_05
    it("on a model — not allowed, use field-level instead", async () => {
      const runner = await Tester.createInstance();
      const diagnostics = await runner.diagnose(`
        ${TASK_ENTITY}

        @projects(Task)
        model TaskProjection { id: string; }
      `);
      expectDiagnostics(diagnostics, {
        code: "@a10n/blueprint-typespec/invalid-decorator-target",
        message: /projects/,
      });
    });

    // a10n:blueprint Components.A10nBlueprintTypespecSdk.Tests.Decorators.T009.T009_06
    it("field targeting an @invariant op — wrong use", async () => {
      const runner = await Tester.createInstance();
      const diagnostics = await runner.diagnose(`
        ${TASK_ENTITY}

        @feature
        namespace Products.MyProduct.Features.MyFeature {
          @invariant(#{
            predicate: "A {@Task} has an id.",
            why: "Reason.",
          })
          op task_has_id(): void;
        }

        model TaskRow {
          @projects(Products.MyProduct.Features.MyFeature.task_has_id)
          id: string;
        }
      `);
      expectDiagnostics(diagnostics, {
        code: "@a10n/blueprint-typespec/projects-field-must-target-entity-field",
        message: /task_has_id/,
      });
    });

    it("field targeting a non-entity model field — wrong use", async () => {
      const runner = await Tester.createInstance();
      const diagnostics = await runner.diagnose(`
        model PlainModel { value: string; }

        model TaskRow {
          @projects(PlainModel.value)
          value: string;
        }
      `);
      expectDiagnostics(diagnostics, {
        code: "@a10n/blueprint-typespec/projects-field-must-target-entity-field",
        message: /value/,
      });
    });

    // a10n:blueprint Components.A10nBlueprintTypespecSdk.Tests.Decorators.T009.T009_07
    it("op targeting an entity field — wrong use", async () => {
      const runner = await Tester.createInstance();
      const diagnostics = await runner.diagnose(`
        ${TASK_ENTITY}

        @component(#{ type: ComponentType.Agent })
        namespace Components.MyAgent {
          @eval(#{ title: "e" })
          namespace Evals.MyFeature.E001 {
            @signal(#{
              title: "s",
              method: SignalMethod.Deterministic,
              criteria: "criteria",
              examples: #[],
            })
            @projects(Task.id)
            op E001_01(): boolean;
          }
        }
      `);
      expectDiagnostics(diagnostics, {
        code: "@a10n/blueprint-typespec/projects-op-must-target-invariant",
        message: /id/,
      });
    });

    it("op targeting a plain op (not @invariant) — wrong use", async () => {
      const runner = await Tester.createInstance();
      const diagnostics = await runner.diagnose(`
        @feature
        namespace Products.MyProduct.Features.MyFeature {
          op plain_op(): void;
        }

        @component(#{ type: ComponentType.Agent })
        namespace Components.MyAgent {
          @eval(#{ title: "e" })
          namespace Evals.MyFeature.E001 {
            @signal(#{
              title: "s",
              method: SignalMethod.Deterministic,
              criteria: "criteria",
              examples: #[],
            })
            @projects(Products.MyProduct.Features.MyFeature.plain_op)
            op E001_01(): boolean;
          }
        }
      `);
      expectDiagnostics(diagnostics, {
        code: "@a10n/blueprint-typespec/projects-op-must-target-invariant",
        message: /plain_op/,
      });
    });

    // a10n:blueprint Components.A10nBlueprintTypespecSdk.Tests.Decorators.T009.T009_08
    it("duplicate @projects on the same field", async () => {
      const runner = await Tester.createInstance();
      const diagnostics = await runner.diagnose(`
        ${TASK_ENTITY}

        model TaskRow {
          @projects(Task.id)
          @projects(Task.id)
          id: string;
        }
      `);
      expectDiagnostics(diagnostics, [
        { code: "@a10n/blueprint-typespec/duplicate-decorator", message: /projects/ },
        { code: "@a10n/blueprint-typespec/duplicate-decorator", message: /projects/ },
      ]);
    });
  });
});
